  1→import { join } from "node:path";
  2→import { getLogger, withContext } from "@logtape/logtape";
  3→import { onError } from "@orpc/server";
  4→import { RPCHandler } from "@orpc/server/fetch";
  5→import { createAuth } from "./auth.js";
  6→import { db } from "./db.js";
  7→import { setupLogging } from "./logging.js";
  8→import { router } from "./router.js";
  9→
 10→await setupLogging();
 11→
 12→const logger = getLogger(["rudel", "api", "http"]);
 13→
 14→const socialProviders: Record<
 15→	string,
 16→	{ clientId: string; clientSecret: string }
 17→> = {};
 18→if (process.env.GOOGLE_CLIENT_ID && process.env.GOOGLE_CLIENT_SECRET) {
 19→	socialProviders.google = {
 20→		clientId: process.env.GOOGLE_CLIENT_ID,
 21→		clientSecret: process.env.GOOGLE_CLIENT_SECRET,
 22→	};
 23→}
 24→if (process.env.GITHUB_CLIENT_ID && process.env.GITHUB_CLIENT_SECRET) {
 25→	socialProviders.github = {
 26→		clientId: process.env.GITHUB_CLIENT_ID,
 27→		clientSecret: process.env.GITHUB_CLIENT_SECRET,
 28→	};
 29→}
 30→
 31→const appURL = process.env.APP_URL ?? "http://localhost:4010";
 32→const trustedOrigins = process.env.TRUSTED_ORIGINS
 33→	? process.env.TRUSTED_ORIGINS.split(",").map((o) => o.trim())
 34→	: ["http://localhost:4011"];
 35→
 36→const auth = createAuth(db, {
 37→	appURL,
 38→	secret: process.env.BETTER_AUTH_SECRET,
 39→	socialProviders,
 40→	trustedOrigins,
 41→	slackWebhookUrl: process.env.SLACK_WEBHOOK_URL,
 42→});
 43→
 44→const rpcHandler = new RPCHandler(router, {
 45→	interceptors: [
 46→		onError((error) => {
 47→			logger.error("RPC unhandled exception: {error} {stack}", {
 48→				error: String(error),
 49→				stack: error instanceof Error ? error.stack : undefined,
 50→			});
 51→		}),
 52→	],
 53→});
 54→
 55→const ALLOWED_ORIGIN = process.env.ALLOWED_ORIGIN ?? "http://localhost:4011";
 56→const STATIC_DIR = join(
 57→	import.meta.dir,
 58→	"..",
 59→	process.env.STATIC_DIR ?? "public",
 60→);
 61→
 62→function corsHeaders(origin: string | null): Record<string, string> {
 63→	if (origin !== ALLOWED_ORIGIN) return {};
 64→	return {
 65→		"Access-Control-Allow-Origin": ALLOWED_ORIGIN,
 66→		"Access-Control-Allow-Credentials": "true",
 67→		"Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, OPTIONS",
 68→		"Access-Control-Allow-Headers": "Content-Type, Authorization",
 69→	};
 70→}
 71→
 72→const port = process.env.PORT ?? 4010;
 73→
 74→const server = Bun.serve({
 75→	port,
 76→	async fetch(request) {
 77→		const origin = request.headers.get("Origin");
 78→		const cors = corsHeaders(origin);
 79→
 80→		if (request.method === "OPTIONS") {
 81→			return new Response(null, { status: 204, headers: cors });
 82→		}
 83→
 84→		const url = new URL(request.url);
 85→
 86→		// Health check for Fly.io (must be GET-accessible)
 87→		if (url.pathname === "/health") {
 88→			return Response.json({ status: "ok", timestamp: Date.now() });
 89→		}
 90→
 91→		const requestId = crypto.randomUUID();
 92→		const start = performance.now();
 93→
 94→		return withContext(
 95→			{ requestId, method: request.method, path: url.pathname },
 96→			async () => {
 97→				const response = await handleRequest(request, url, cors);
 98→				const duration = Math.round(performance.now() - start);
 99→				logger.info("{method} {path} {status} {duration}ms", {
100→					method: request.method,
101→					path: url.pathname,
102→					status: response.status,
103→					duration,
104→				});
105→				return response;
106→			},
107→		);
108→	},
109→});
110→
111→async function handleRequest(
112→	request: Request,
113→	url: URL,
114→	cors: Record<string, string>,
115→): Promise<Response> {
116→	if (url.pathname === "/api/cli-token") {
117→		const session = await auth.api.getSession({
118→			headers: request.headers,
119→		});
120→		if (!session) {
121→			return new Response(JSON.stringify({ error: "Not authenticated" }), {
122→				status: 401,
123→				headers: { ...cors, "Content-Type": "application/json" },
124→			});
125→		}
126→		return new Response(JSON.stringify({ token: session.session.token }), {
127→			status: 200,
128→			headers: { ...cors, "Content-Type": "application/json" },
129→		});
130→	}
131→
132→	// Defense in depth: block Better Auth's built-in org deletion route.
133→	// Rudel has its own guarded deletion path via the RPC router.
134→	if (url.pathname === "/api/auth/organization/delete") {
135→		return new Response("Not Found", { status: 404, headers: cors });
136→	}
137→
138→	if (url.pathname.startsWith("/api/auth")) {
139→		const response = await auth.handler(request);
140→		for (const [key, value] of Object.entries(cors)) {
141→			response.headers.set(key, value);
142→		}
143→		return response;
144→	}
145→
146→	const { matched, response } = await rpcHandler.handle(request, {
147→		prefix: "/rpc",
148→		context: await getContext(request),
149→	});
150→
151→	if (matched) {
152→		if (response.status >= 500) {
153→			const body = await response.clone().text();
154→			logger.error("RPC error on {path}: {status} {body}", {
155→				path: url.pathname,
156→				status: response.status,
157→				body,
158→			});
159→		}
160→		for (const [key, value] of Object.entries(cors)) {
161→			response.headers.set(key, value);
162→		}
163→		return response;
164→	}
165→
166→	// Static file serving (production: frontend assets)
167→	const filePath = join(STATIC_DIR, url.pathname);
168→	const file = Bun.file(filePath);
169→	if (await file.exists()) {
170→		return new Response(file);
171→	}
172→
173→	// SPA fallback: serve index.html for non-API routes
174→	const indexFile = Bun.file(join(STATIC_DIR, "index.html"));
175→	if (await indexFile.exists()) {
176→		return new Response(indexFile);
177→	}
178→
179→	// Dev mode: redirect to frontend dev server for non-API routes
180→	// (e.g., after OAuth callback redirects to APP_URL which has no SPA)
181→	if (ALLOWED_ORIGIN !== appURL) {
182→		return Response.redirect(
183→			`${ALLOWED_ORIGIN}${url.pathname}${url.search}`,
184→			302,
185→		);
186→	}
187→
188→	return new Response("Not found", { status: 404, headers: cors });
189→}
190→
191→async function getContext(request: Request) {
192→	const session = await auth.api.getSession({
193→		headers: request.headers,
194→	});
195→	return {
196→		user: session?.user ?? null,
197→		session: session?.session ?? null,
198→	};
199→}
200→
201→logger.info("API server listening on http://localhost:{port}", {
202→	port: server.port,
203→});
204→

  1→import { ORPCError } from "@orpc/server";
  2→import { getAdapter } from "@rudel/agent-adapters";
  3→import { member, organization, session } from "@rudel/sql-schema";
  4→import { and, eq } from "drizzle-orm";
  5→import { getClickhouse } from "./clickhouse.js";
  6→import { db } from "./db.js";
  7→import { analyticsRouter } from "./handlers/analytics/index.js";
  8→import { authMiddleware, os } from "./middleware.js";
  9→import {
 10→	deleteOrgSessions,
 11→	getOrgSessionCount,
 12→} from "./services/org-session.service.js";
 13→
 14→const health = os.health.handler(() => {
 15→	return {
 16→		status: "ok" as const,
 17→		timestamp: Date.now(),
 18→	};
 19→});
 20→
 21→const me = os.me.use(authMiddleware).handler(({ context }) => {
 22→	return {
 23→		id: context.user.id,
 24→		email: context.user.email,
 25→		name: context.user.name,
 26→		image: context.user.image ?? null,
 27→		activeOrganizationId:
 28→			((context.session as Record<string, unknown>).activeOrganizationId as
 29→				| string
 30→				| null) ?? null,
 31→	};
 32→});
 33→
 34→const listMyOrganizations = os.listMyOrganizations
 35→	.use(authMiddleware)
 36→	.handler(async ({ context }) => {
 37→		const memberships = await db
 38→			.select({
 39→				id: organization.id,
 40→				name: organization.name,
 41→				slug: organization.slug,
 42→				logo: organization.logo,
 43→			})
 44→			.from(member)
 45→			.innerJoin(organization, eq(member.organizationId, organization.id))
 46→			.where(eq(member.userId, context.user.id));
 47→
 48→		return memberships.map((m) => ({
 49→			id: m.id,
 50→			name: m.name,
 51→			slug: m.slug,
 52→			logo: m.logo ?? null,
 53→		}));
 54→	});
 55→
 56→const ingestSessionHandler = os.ingestSession
 57→	.use(authMiddleware)
 58→	.handler(async ({ input, context }) => {
 59→		const orgId =
 60→			input.organizationId ??
 61→			((context.session as Record<string, unknown>).activeOrganizationId as
 62→				| string
 63→				| null) ??
 64→			context.user.id;
 65→
 66→		// Verify membership for any org that isn't the user's personal workspace
 67→		if (orgId !== context.user.id) {
 68→			const membership = await db
 69→				.select({ id: member.id })
 70→				.from(member)
 71→				.where(
 72→					and(
 73→						eq(member.organizationId, orgId),
 74→						eq(member.userId, context.user.id),
 75→					),
 76→				)
 77→				.limit(1);
 78→
 79→			if (membership.length === 0) {
 80→				throw new ORPCError("FORBIDDEN", {
 81→					message: "Not a member of the specified organization",
 82→				});
 83→			}
 84→		}
 85→
 86→		const adapter = getAdapter(input.source);
 87→		await adapter.ingest(getClickhouse(), input, {
 88→			userId: context.user.id,
 89→			organizationId: orgId,
 90→		});
 91→
 92→		return {
 93→			success: true as const,
 94→			sessionId: input.sessionId,
 95→		};
 96→	});
 97→
 98→const getOrganizationSessionCount = os.getOrganizationSessionCount
 99→	.use(authMiddleware)
100→	.handler(async ({ input, context }) => {
101→		const membership = await db
102→			.select({ id: member.id })
103→			.from(member)
104→			.where(
105→				and(
106→					eq(member.organizationId, input.organizationId),
107→					eq(member.userId, context.user.id),
108→				),
109→			)
110→			.limit(1);
111→
112→		if (membership.length === 0) {
113→			throw new ORPCError("FORBIDDEN", {
114→				message: "Not a member of this organization",
115→			});
116→		}
117→
118→		const count = await getOrgSessionCount(input.organizationId);
119→		return { count };
120→	});
121→
122→const deleteOrganization = os.deleteOrganization
123→	.use(authMiddleware)
124→	.handler(async ({ input, context }) => {
125→		const orgId = input.organizationId;
126→		const userId = context.user.id;
127→		console.log(`[deleteOrganization] user=${userId} org=${orgId}`);
128→
129→		// Check user has more than one org
130→		const memberships = await db
131→			.select({ organizationId: member.organizationId })
132→			.from(member)
133→			.where(eq(member.userId, userId));
134→
135→		if (memberships.length <= 1) {
136→			console.log(
137→				`[deleteOrganization] rejected: user=${userId} has only ${memberships.length} org(s)`,
138→			);
139→			throw new ORPCError("BAD_REQUEST", {
140→				message: "Cannot delete your only organization",
141→			});
142→		}
143→
144→		// Verify user is owner of the target org
145→		const ownership = await db
146→			.select({ id: member.id })
147→			.from(member)
148→			.where(
149→				and(
150→					eq(member.organizationId, orgId),
151→					eq(member.userId, userId),
152→					eq(member.role, "owner"),
153→				),
154→			)
155→			.limit(1);
156→
157→		if (ownership.length === 0) {
158→			console.log(
159→				`[deleteOrganization] rejected: user=${userId} is not owner of org=${orgId}`,
160→			);
161→			throw new ORPCError("FORBIDDEN", {
162→				message: "Only the organization owner can delete it",
163→			});
164→		}
165→
166→		try {
167→			// Fire-and-forget: ClickHouse mutations are slow, don't block on them
168→			deleteOrgSessions(orgId);
169→
170→			// Delete the organization from Postgres (cascade handles member + invitation)
171→			console.log(`[deleteOrganization] deleting org=${orgId} from Postgres`);
172→			await db.delete(organization).where(eq(organization.id, orgId));
173→
174→			// Clear activeOrganizationId on user sessions that reference the deleted org
175→			console.log(
176→				`[deleteOrganization] clearing activeOrganizationId references for org=${orgId}`,
177→			);
178→			await db
179→				.update(session)
180→				.set({ activeOrganizationId: null })
181→				.where(eq(session.activeOrganizationId, orgId));
182→
183→			console.log(`[deleteOrganization] success for org=${orgId}`);
184→			return { success: true as const };
185→		} catch (error) {
186→			if (error instanceof ORPCError) throw error;
187→			console.error(`[deleteOrganization] failed for org=${orgId}:`, error);
188→			throw error;
189→		}
190→	});
191→
192→export const router = os.router({
193→	health,
194→	me,
195→	listMyOrganizations,
196→	ingestSession: ingestSessionHandler,
197→	getOrganizationSessionCount,
198→	deleteOrganization,
199→	analytics: analyticsRouter,
200→});
