287→	private buildRow(
288→		input: IngestSessionInput,
289→		context: IngestContext,
290→	): RudelClaudeSessionsRow {
291→		const now = new Date().toISOString().replace("Z", "");
292→
293→		const subagents: Record<string, string> = {};
294→		if (input.subagents) {
295→			for (const sub of input.subagents) {
296→				subagents[sub.agentId] = sub.content;
297→			}
298→		}
299→
300→		const timestamps = this.extractTimestamps(input.content);
301→
302→		return {
303→			session_date: timestamps
304→				? toClickHouseDateTime(timestamps.sessionDate)
305→				: now,
306→			last_interaction_date: timestamps
307→				? toClickHouseDateTime(timestamps.lastInteractionDate)
308→				: now,
309→			session_id: input.sessionId,
310→			organization_id: context.organizationId,
311→			project_path: input.projectPath,
312→			git_remote: input.gitRemote ?? "",
313→			package_name: input.packageName ?? "",
314→			package_type: input.packageType ?? "",
315→			content: input.content,
316→			subagents,
317→			ingested_at: now,
318→			user_id: context.userId,
319→			git_branch: input.gitBranch ?? null,
320→			git_sha: input.gitSha ?? null,
321→			tag: input.tag ?? null,
322→		};
323→	}
