 1→import { implement, ORPCError } from "@orpc/server";
 2→import { contract } from "@rudel/api-routes";
 3→import { member } from "@rudel/sql-schema";
 4→import { and, eq } from "drizzle-orm";
 5→import type { Session } from "./auth.js";
 6→import { db } from "./db.js";
 7→
 8→export interface AppContext {
 9→	user: Session["user"] | null;
10→	session: Session["session"] | null;
11→}
12→
13→export const os = implement(contract).$context<AppContext>();
14→
15→export const authMiddleware = os.middleware(async ({ context, next }) => {
16→	if (!context.user || !context.session) {
17→		throw new ORPCError("UNAUTHORIZED");
18→	}
19→	return next({
20→		context: {
21→			user: context.user,
22→			session: context.session,
23→		},
24→	});
25→});
26→
27→export const orgMiddleware = os.middleware(async ({ context, next }) => {
28→	if (!context.user || !context.session) {
29→		throw new ORPCError("UNAUTHORIZED");
30→	}
31→	const organizationId =
32→		(context.session as Record<string, unknown>).activeOrganizationId ??
33→		context.user.id;
34→	if (!organizationId || typeof organizationId !== "string") {
35→		throw new ORPCError("BAD_REQUEST", {
36→			message: "No active organization",
37→		});
38→	}
39→
40→	// When the active org is not the user's personal workspace, verify membership
41→	if (organizationId !== context.user.id) {
42→		const membership = await db
43→			.select({ id: member.id })
44→			.from(member)
45→			.where(
46→				and(
47→					eq(member.organizationId, organizationId),
48→					eq(member.userId, context.user.id),
49→				),
50→			)
51→			.limit(1);
52→
53→		if (membership.length === 0) {
54→			throw new ORPCError("FORBIDDEN", {
55→				message: "Not a member of the active organization",
56→			});
57→		}
58→	}
59→
60→	return next({
61→		context: {
62→			user: context.user,
63→			session: context.session,
64→			organizationId,
65→		},
66→	});
67→});
