interface RateLimitConfig {
	/**
	 * Maximum number of requests allowed in the window.
	 */
	maxRequests: number;
	/**
	 * Time window in seconds.
	 */
	windowSeconds: number;
	/**
	 * ClickHouse table to count against.
	 */
	table: string;
	/**
	 * Column to use for timestamp filtering. Must be DateTime64.
	 */
	timeColumn?: string;
}

const DEFAULT_INGEST_RATE_LIMIT: RateLimitConfig = {
	maxRequests: Number(process.env.RATE_LIMIT_INGEST_MAX ?? 120),
	windowSeconds: Number(process.env.RATE_LIMIT_INGEST_WINDOW ?? 3600),
	table: "rudel.claude_sessions",
	timeColumn: "ingested_at",
};

