import { ORPCError } from "@orpc/server";
import { getLogger } from "@logtape/logtape";
import { queryClickhouse, escapeString } from "./clickhouse.js";
import type { AppContext } from "./middleware.js";
import { os } from "./middleware.js";

const logger = getLogger(["rudel", "api", "rate-limit"]);

interface RateLimitConfig {
	/**
	 * Maximum number of requests allowed in the window.
	 */
	maxRequests: number;
	/**
	 * Time window in seconds.
	 */
	windowSeconds: number;
	/**
	 * ClickHouse table to count against.
	 */
	table: string;
	/**
	 * Column to use for timestamp filtering. Must be DateTime64.
	 */
	timeColumn?: string;
}

const DEFAULT_INGEST_RATE_LIMIT: RateLimitConfig = {
	maxRequests: Number(process.env.RATE_LIMIT_INGEST_MAX ?? 120),
	windowSeconds: Number(process.env.RATE_LIMIT_INGEST_WINDOW ?? 3600),
	table: "rudel.claude_sessions",
	timeColumn: "ingested_at",
};

/**
 * Creates an oRPC middleware that enforces per-user rate limits
 * by querying ClickHouse for recent writes.
 *
 * This is designed for write-path endpoints (ingest) where the
 * ClickHouse table already records the user_id and a timestamp.
 */
export function createWriteRateLimitMiddleware(
	config: Partial<RateLimitConfig> = {},
) {
	const { maxRequests, windowSeconds, table, timeColumn } = {
		...DEFAULT_INGEST_RATE_LIMIT,
		...config,
	};

	return os.middleware(async ({ context, next }) => {
		const userId = context.user?.id;
		if (!userId) {
			// Auth middleware should catch this first, but be safe
			throw new ORPCError("UNAUTHORIZED");
		}

		try {
			const rows = await queryClickhouse<{ count: number }>(
				`SELECT count() AS count FROM ${table} WHERE user_id = '${escapeString(userId)}' AND ${timeColumn} >= now64(3) - INTERVAL ${windowSeconds} SECOND`,
			);
			const count = rows[0]?.count ?? 0;

			if (count >= maxRequests) {
				logger.warn(
					"Rate limit exceeded for user {userId}: {count}/{maxRequests} in {windowSeconds}s",
					{ userId, count, maxRequests, windowSeconds },
				);
				throw new ORPCError("TOO_MANY_REQUESTS", {
					message: `Rate limit exceeded. Maximum ${maxRequests} requests per ${Math.round(windowSeconds / 60)} minutes.`,
				});
			}
		} catch (error) {
			if (error instanceof ORPCError) throw error;
			// If ClickHouse is down, log and allow the request through.
			// Availability > rate limiting.
			logger.error("Rate limit check failed, allowing request: {error}", {
				error,
			});
		}

		return next({ context });
	});
}

export const ingestRateLimitMiddleware = createWriteRateLimitMiddleware();

