28→	if (!context.user || !context.session) {
29→		throw new ORPCError("UNAUTHORIZED");
30→	}
31→	const organizationId =
32→		(context.session as Record<string, unknown>).activeOrganizationId ??
33→		context.user.id;
34→	if (!organizationId || typeof organizationId !== "string") {
35→		throw new ORPCError("BAD_REQUEST", {
36→			message: "No active organization",
37→		});
38→	}
39→
40→	// When the active org is not the user's personal workspace, verify membership
41→	if (organizationId !== context.user.id) {
42→		const membership = await db
43→			.select({ id: member.id })
44→			.from(member)
45→			.where(
46→				and(
47→					eq(member.organizationId, organizationId),
48→					eq(member.userId, context.user.id),
49→				),
50→			)
51→			.limit(1);
52→
53→		if (membership.length === 0) {
54→			throw new ORPCError("FORBIDDEN", {
55→				message: "Not a member of the active organization",
56→			});
57→		}
58→	}
59→
60→	return next({
61→		context: {
62→			user: context.user,
63→			session: context.session,
64→			organizationId,
65→		},
66→	});
